package commands

import (
	"context"
	"fmt"

	"golang.org/x/sync/errgroup"
)

type EnrollCourseUsecaseParams struct {
	userId        string
	courseId      string
	sectionNumber *int
	topicNumber   *int
}

type EnrollCourseUsecase struct {
	courseRepository   CourseRepository
	progressRepository ProgressRepository
}

func NewEnrollCourseUsecase(courseRepo CourseRepository, progressRepo ProgressRepository) EnrollCourseUsecase {
	return EnrollCourseUsecase{
		courseRepository:   courseRepo,
		progressRepository: progressRepo,
	}
}

type CourseRepository interface {
	getCourseByCourseId(ctx context.Context, courseId string) (Course, error)
}

type ProgressRepository interface {
	getProgress(ctx context.Context, userId string, courseId string) (Progress, error)
	save(ctx context.Context, progress *Progress) error
}

type EnrollCourseUsecaseInterface interface {
	execute(ctx context.Context, params EnrollCourseUsecaseParams) (string, error)
}

func (usecase EnrollCourseUsecase) execute(ctx context.Context, params EnrollCourseUsecaseParams) (string, error) {
	var course Course
	var progress Progress

	g, gctx := errgroup.WithContext(ctx)
	g.Go(func() error {
		var err error
		course, err = usecase.courseRepository.getCourseByCourseId(gctx, params.courseId)
		return err
	})
	g.Go(func() error {
		var err error
		progress, err = usecase.progressRepository.getProgress(gctx, params.userId, params.courseId)
		return err
	})

	if err := g.Wait(); err != nil {
		return "", err
	}

	fmt.Printf("[DEBUG] progress: %+v\n", progress)

	if err := course.checkEnrollable(params.userId); err != nil {
		return "", err
	}

	ltp := progress.lastTopicPosition()
	fmt.Printf("[DEBUG] progress: %+v\n", ltp)

	section, topic, err := course.findTopicToStart(params.sectionNumber, params.topicNumber, ltp)

	fmt.Printf("[DEBUG] progress: %+v\n%+v", section, topic)

	if err != nil {
		return "", err
	}

	topicId := progress.start(section, topic)

	return topicId, usecase.progressRepository.save(ctx, &progress)
}

content.text:
このコードを題材に、**goroutine の基本 → `errgroup` なし → `errgroup` あり** の順で説明します。

---

## goroutine の基本

```go
go func() {
    // 別スレッドで実行される
}()
```

`go` キーワードをつけるだけで並行実行できます。ただし、**終了待ち・エラー伝播**が自前になります。

---

## errgroup なし版（channel で書く）

```go
func (usecase EnrollCourseUsecase) execute(ctx context.Context, params EnrollCourseUsecaseParams) (string, error) {
    type courseResult struct {
        course Course
        err    error
    }
    type progressResult struct {
        progress Progress
        err      error
    }

    courseCh   := make(chan courseResult, 1)
    progressCh := make(chan progressResult, 1)

    // goroutine 1: コース取得
    go func() {
        c, err := usecase.courseRepository.getCourseByCourseId(ctx, params.courseId)
        courseCh <- courseResult{c, err}
    }()

    // goroutine 2: 進捗取得
    go func() {
        p, err := usecase.progressRepository.getProgress(ctx, params.userId, params.courseId)
        progressCh <- progressResult{p, err}
    }()

    // 両方の結果を待つ
    cr := <-courseCh
    pr := <-progressCh

    if cr.err != nil {
        return "", cr.err
    }
    if pr.err != nil {
        return "", pr.err
    }

    course    := cr.course
    progress  := pr.progress
    // ... 以降同じ
}
```

**ポイント：**
- `make(chan T, 1)` — バッファ付き channel。goroutine が結果を送って終了できる
- `<-courseCh` — 値が届くまでブロックして待つ
- エラー処理は自分で順番に確認する必要がある

---

## errgroup あり版（現在のコード）

```go
g, gctx := errgroup.WithContext(ctx)

g.Go(func() error {
    var err error
    course, err = usecase.courseRepository.getCourseByCourseId(gctx, params.courseId)
    return err
})
g.Go(func() error {
    var err error
    progress, err = usecase.progressRepository.getProgress(gctx, params.userId, params.courseId)
    return err
})

if err := g.Wait(); err != nil {
    return "", err  // 最初に発生したエラーが返る
}
```

---

## 比較まとめ

| | channel 版 | errgroup 版 |
|---|---|---|
| コード量 | 多い（型・channel 定義が必要） | 少ない |
| エラーハンドリング | 自前で全部チェック | `g.Wait()` 一行 |
| キャンセル伝播 | 自前で `ctx` に乗せる必要あり | `gctx` で自動（1つ失敗→他もキャンセル） |
| 依存ライブラリ | なし（標準）| `golang.org/x/sync` |

**errgroup の最大のメリット**は `gctx` です。一方の goroutine がエラーを返すと、`gctx` がキャンセルされるため、もう一方の処理も（context を見ていれば）自動的に中断されます。

このコードのように「2つの独立した取得処理を並行して行い、どちらかが失敗したら即座に止めたい」ケースには `errgroup` が最適です。
